mapper.insert:
/** UsptBsnsRecomendClDao.insert */
insert into uspt_bsns_recomend_cl
					(
						bsns_cd
						, recomend_cl_type_cd
						, recomend_cl_cd
						, creator_id
						, created_dt
					)
			values	(
						#{bsnsCd}
						, #{recomendClTypeCd}
						, #{recomendClCd}
						, #{creatorId}
						, #{createdDt}
					)

/** UsptBsnsRecomendClDao.insertList */
insert into uspt_bsns_recomend_cl
	(
		bsns_cd
		, recomend_cl_type_cd
		, recomend_cl_cd
		, creator_id
		, created_dt
	) values

	(
		#{item.bsnsCd}
		,#{item.recomendClTypeCd}
		,#{item.recomendClCd}
		,#{item.creatorId}
		,#{item.createdDt}
	)

mapper.delete:
/** UsptBsnsRecomendClDao.deleteAll */
delete from uspt_bsns_recomend_cl
where
	bsns_cd = #{bsnsCd}
